DROP TABLE IF EXISTS `IE_008_802_INC`;
CREATE TABLE `IE_008_802_INC` (
  `DFXH`                   VARCHAR(30)      DEFAULT NULL COMMENT '对方行号；交易对手的银行机构代码。1. 交易对手为境外账户时，对方行号可填SWIFT编码。2. 该笔明细交易是转账交易的，对方账号和对方户名必须填实际收款人，不可填中间过渡账户或清算账户。3. 交易对手是第三方支付平台账号的，对方账号填报为交易对手第三方支付账号，对方户名填报为交易对手的第三方支付户名，对方行名填报为第三方支付平台名称，对方行号允许为空。4. 对于代收、代扣、代缴等交易的，对方账号和对方户名必须填实际收款人，不可填中间过渡账户或清算账户；对于代发等代付业务，交易对手为多个的，允许交易对手可以登记为中间过渡账户。5. 对方账号与对方户名必须一致，对应同一实体。6. 若对方账户是境内银行机构开立的账户，则对方行号必须是12位人行支付行号，对方行名必须是与人行支付行号对应的银行机构名称。分支机构如没有人行支付行号，可填写最近的上一级管理机构支付行号。各行应从官方渠道获得一份官方发布的人行支付行号及行名字典表，确保对方行号填写的人行支付行号与对方行名保持一致。7. 消费、退货、计提利息、计提手续费、手工调账等交易，交易对手填实际转入或转出的外部账户或内部分户账，并在摘要中注明，不可为空。',
  `SHMC`                   VARCHAR(450)     DEFAULT NULL COMMENT '商户名称；指持卡人实际支付的商户名称。若不涉及商户，可以为空。',
  `XSXXJYBZ`               VARCHAR(6)       DEFAULT NULL COMMENT '线上线下交易标志；线下交易包括POS机刷卡，自助机取现等交易，线上交易包括网上银行、手机支付、二维码支付等交易。',
  `SXFJE`                  DECIMAL(20,2)    DEFAULT NULL COMMENT '手续费金额；填写本行收取客户的手续费金额，如果没有手续费填写默认值0。',
  `JYZDRQ`                 VARCHAR(8)       DEFAULT NULL COMMENT '交易账单日期；填写该笔交易对应的账单日期。如果为消费交易，填报交易后最近的账单出账日期。如果为还款交易，填报为空。',
  `ZJLB`                   VARCHAR(60)      DEFAULT NULL COMMENT '证件类别；持卡人证件类别',
  `KPJYLX`                 VARCHAR(60)      DEFAULT NULL COMMENT '卡片交易类型；无法以枚举类型填报的，以“XX”报送，其中“XX”为银行自定义类型。“现金交易”包括如现金借款、ATM取现等非消费类交易。“转账交易”主要针对贷记卡及准贷记卡的转账交易。退换类交易包含在“消费交易”。',
  `SENSITIVEFLAG`          VARCHAR(30)      DEFAULT NULL COMMENT '涉密标志',
  `HXJYRQ`                 VARCHAR(8)       DEFAULT NULL COMMENT '核心交易日期；PK。填刷卡日期，对于余额结转记录为余额结转日期。',
  `BZ`                     VARCHAR(3)       DEFAULT NULL COMMENT '币种；该笔交易的币种。',
  `JRXKZH`                 VARCHAR(30)      DEFAULT NULL COMMENT '金融许可证号；填报信用卡归属的银行机构。关联数据项：机构信息表.金融许可证号',
  `MXKMMC`                 VARCHAR(300)     DEFAULT NULL COMMENT '明细科目名称；同一条数据涉及多个明细科目的，仅填报该笔业务指向的主要科目，如：一笔贷款仅包含正常本金时，填报正常本金科目，如一笔贷款既包含正常本金也包含逾期本金时，填报逾期本金科目。关联数据项：总账会计全科目表.会计科目编号。',
  `JYXLH`                  VARCHAR(100)     DEFAULT NULL COMMENT '交易序列号；PK。',
  `YHJGMC`                 VARCHAR(450)     DEFAULT NULL COMMENT '银行机构名称；填报信用卡归属的银行机构。关联数据项：机构信息表.银行机构名称。',
  `KHTYBH`                 VARCHAR(70)      DEFAULT NULL COMMENT '客户统一编号；如包含个人身份证件号码，则为隐私，银行机构需做变形，变形规则见《采集技术接口说明》。关联数据项：个人基础信息表.客户统一编号 或对公客户信息表.客户统一编号',
  `KHMC`                   VARCHAR(450)     DEFAULT NULL COMMENT '客户名称；如果是个人客户，则为隐私，银行机构变形，变形规则见《采集技术接口说明》。关联数据项：个人基础信息表.客户姓名 或 对公客户信息表.客户名称',
  `ZJHM`                   VARCHAR(70)      DEFAULT NULL COMMENT '证件号码；持卡人证件号码。隐私，银行机构变形。变形规则见《采集技术接口说明》。',
  `XYKZH`                  VARCHAR(60)      DEFAULT NULL COMMENT '信用卡账号；关联数据项：信用卡信息表.信用卡账号',
  `KH`                     VARCHAR(60)      DEFAULT NULL COMMENT '卡号；PK。关联数据项：信用卡信息表.卡号',
  `JYJDBZ`                 VARCHAR(3)       DEFAULT NULL COMMENT '交易借贷标志',
  `HXJYSJ`                 VARCHAR(6)       DEFAULT NULL COMMENT '核心交易时间；PK。本笔交易在核心系统的交易时间。',
  `ZHYE`                   DECIMAL(20,2)    DEFAULT NULL COMMENT '账户余额；本笔交易时点完成后该时点包含包含本金、手续费、利息、滞纳金、罚金、罚息的账户余额。存在溢缴款时账户余额为负，否则为正。',
  `DFZH`                   VARCHAR(60)      DEFAULT NULL COMMENT '对方账号；客户往账业务对应传票上记载的最终交易对手信息。1. 交易标志为“线上”时，交易对手信息必填；交易标志为“线下”，交易渠道为“POS”时，交易对手信息必填。2. 该笔明细交易是转账交易的，对方账号和对方户名必须填实际收款人，不可填中间过渡账户或清算账户。3. 交易对手是第三方支付平台账号的，对方账号填报为交易对手第三方支付账号，对方户名填报为交易对手的第三方支付户名，对方行名填报为第三方支付平台名称，对方行号允许为空。4. 对于代收、代扣、代缴等交易的，对方账号和对方户名必须填实际收款人，不可填中间过渡账户或清算账户；对于代发等代付业务，交易对手为多个的，允许交易对手可以登记为中间过渡账户。5. 对方账号与对方户名必须一致，对应同一实体。6. 若对方账户是境内银行机构开立的账户，则对方行号必须是12位人行支付行号，对方行名必须是与人行支付行号对应的银行机构名称。分支机构如没有人行支付行号，可填写最近的上一级管理机构支付行号。各行应从官方渠道获得一份官方发布的人行支付行号及行名字典表，确保对方行号填写的人行支付行号与对方行名保持一致。7. 消费、退货、计提利息、计提手续费、手工调账等交易，交易对手填实际转入或转出的外部账户或内部分户账，并在摘要中注明交易类型，不可为空。',
  `DFHM`                   VARCHAR(450)     DEFAULT NULL COMMENT '对方户名；交易对手的开户名称。若交易对手为个人，则为隐私，银行机构变形，填写个人姓名最后一个字。其他情况则为非隐私，不做变形。1. 交易标志为“线上”时，交易对手信息必填；交易标志为“线下”，交易渠道为“POS”时，交易对手信息必填。2. 该笔明细交易是转账交易的，对方账号和对方户名必须填实际收款人，不可填中间过渡账户或清算账户。3. 交易对手是第三方支付平台账号的，对方账号填报为交易对手第三方支付账号，对方户名填报为交易对手的第三方支付户名，对方行名填报为第三方支付平台名称，对方行号允许为空。4. 对于代收、代扣、代缴等交易的，对方账号和对方户名必须填实际收款人，不可填中间过渡账户或清算账户；对于代发等代付业务，交易对手为多个的，允许交易对手可以登记为中间过渡账户。5. 对方账号与对方户名必须一致，对应同一实体。6. 若对方账户是境内银行机构开立的账户，则对方行号必须是12位人行支付行号，对方行名必须是与人行支付行号对应的银行机构名称。分支机构如没有人行支付行号，可填写最近的上一级管理机构支付行号。各行应从官方渠道获得一份官方发布的人行支付行号及行名字典表，确保对方行号填写的人行支付行号与对方行名保持一致。7. 消费、退货、计提利息、计提手续费、手工调账等交易，交易对手填实际转入或转出的外部账户或内部分户账，并在摘要中注明，不可为空。',
  `DFXM`                   VARCHAR(450)     DEFAULT NULL COMMENT '对方行名；交易对手的银行机构名称。1. 交易对手为境外账户时，对方行名可填报英文名称。2. 该笔明细交易是转账交易的，对方账号和对方户名必须填实际收款人，不可填中间过渡账户或清算账户。3. 交易对手是第三方支付平台账号的，对方账号填报为交易对手第三方支付账号，对方户名填报为交易对手的第三方支付户名，对方行名填报为第三方支付平台名称，对方行号允许为空。4. 对于代收、代扣、代缴等交易的，对方账号和对方户名必须填实际收款人，不可填中间过渡账户或清算账户；对于代发等代付业务，交易对手为多个的，允许交易对手可以登记为中间过渡账户。5. 对方账号与对方户名必须一致，对应同一实体。6. 若对方账户是境内银行机构开立的账户，则对方行号必须是12位人行支付行号，对方行名必须是与人行支付行号对应的银行机构名称。分支机构如没有人行支付行号，可填写最近的上一级管理机构支付行号。各行应从官方渠道获得一份官方发布的人行支付行号及行名字典表，确保对方行号填写的人行支付行号与对方行名保持一致。7. 消费、退货、计提利息、计提手续费、手工调账等交易，交易对手填实际转入或转出的外部账户或内部分户账，并在摘要中注明，不可为空。',
  `SHBH`                   VARCHAR(200)     DEFAULT NULL COMMENT '商户编号；指持卡人实际支付的商户编号，不仅包括银行自有商户编号，第三方支付机构收单对应的交易也需填报商户编号。若不涉及商户，允许为空。',
  `ZY`                     VARCHAR(600)     DEFAULT NULL COMMENT '摘要',
  `SXFBZ`                  VARCHAR(3)       DEFAULT NULL COMMENT '手续费币种；填写本行收取客户的手续费币种，如果没有手续费允许为空。',
  `ZCHKRQ`                 VARCHAR(8)       DEFAULT NULL COMMENT '最迟还款日期；如果为消费交易，填报交易对应的最后还款日（含宽限期）。如果为还款交易，填报为空。',
  `IPDZ`                   VARCHAR(40)      DEFAULT NULL COMMENT 'IP地址；若交易渠道为商户POS，填报刷卡终端的IP地址。若交易渠道为网银、手机银行，填写交易发起终端的IP地址。其他情况允许为空。',
  `MACDZ`                  VARCHAR(60)      DEFAULT NULL COMMENT 'MAC地址；若交易渠道为商户POS，填报刷卡终端的设备地址。若交易渠道为网银、手机银行，需填写交易发起终端的设备地址。其他情况允许为空。',
  `CJRQ`                   VARCHAR(8)       DEFAULT NULL COMMENT '采集日期；PK。采集日期指该期（批次）数据报送的期末日期，例如：按日采集的表，采集日期应为每日；按月采集的表，采集日期应为月末最后一天；以此类推。有特殊报送要求的，应以报送要求的截至日期为采集日期。',
  `DFKHLB`                 VARCHAR(6)       DEFAULT NULL COMMENT '对方客户类别',
  `TQJQBZ`                 VARCHAR(3)       DEFAULT NULL COMMENT '提前结清标志；分期业务提前结清标志。',
  `JYQD`                   VARCHAR(60)      DEFAULT NULL COMMENT '交易渠道；同时存在多个交易渠道的以英文半角分号“;”分隔填报',
  `BBZ`                    VARCHAR(600)     DEFAULT NULL COMMENT '备注；描述其他字段未能详尽说明的情况，或标注对本条报送记录的特殊说明（如视需要可用于说明各种不满足检核规则的例外情况：客户信息表中可标注“境外客户”“客户已工商注销”“客户名下账户均已管控”，信贷分户账中可标注“线上化业务”“自助类贷款”等）。不同备注事项用英文半角分号隔开。',
  `NBJGH`                  VARCHAR(30)      DEFAULT NULL COMMENT '内部机构号；填报信用卡归属的银行机构。关联数据项：机构信息表.内部机构号。',
  `GSFZJG`                 VARCHAR(200)     DEFAULT NULL COMMENT '归属分支机构',
  `MXKMBH`                 VARCHAR(60)      DEFAULT NULL COMMENT '明细科目编号；同一条数据涉及多个明细科目的，仅填报该笔业务指向的主要科目，如：一笔贷款仅包含正常本金时，填报正常本金科目，如一笔贷款既包含正常本金也包含逾期本金时，填报逾期本金科目。关联数据项：总账会计全科目表.会计科目编号。',
  `KHLB`                   VARCHAR(6)       DEFAULT NULL COMMENT '客户类别',
  `JYJE`                   DECIMAL(20,2)    DEFAULT NULL COMMENT '交易金额',
  `FQFKBZ`                 VARCHAR(3)       DEFAULT NULL COMMENT '分期付款标志；填报为：“是”或“否”'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='信用卡交易明细表';
